// Global Error Handler & Retry Supervisor
// Analyzes errors, implements intelligent retry logic, and manages escalation

const errorData = $input.first();
const workflowId = $workflow.id;
const executionId = $execution.id;
const timestamp = new Date().toISOString();

// Extract error information
const errorInfo = {
  workflowId,
  executionId,
  timestamp,
  nodeName: errorData.node?.name || 'Unknown',
  nodeType: errorData.node?.type || 'Unknown',
  errorMessage: errorData.error?.message || 'Unknown error',
  errorStack: errorData.error?.stack || '',
  errorCode: errorData.error?.code || 'UNKNOWN',
  httpStatusCode: errorData.error?.httpStatusCode || null
};

// Classify error type and determine retry strategy
function classifyError(error) {
  const message = error.errorMessage.toLowerCase();
  const httpCode = error.httpStatusCode;

  // Rate limiting errors
  if (httpCode === 429 || message.includes('rate limit') || message.includes('too many requests')) {
    return {
      type: 'RATE_LIMIT',
      retryable: true,
      retryDelay: 300000, // 5 minutes
      maxRetries: 3,
      escalationLevel: 'LOW'
    };
  }

  // Authentication errors
  if (httpCode === 401 || httpCode === 403 || message.includes('unauthorized') || message.includes('forbidden')) {
    return {
      type: 'AUTH_ERROR',
      retryable: false,
      retryDelay: 0,
      maxRetries: 0,
      escalationLevel: 'HIGH'
    };
  }

  // Network/timeout errors
  if (httpCode >= 500 || message.includes('timeout') || message.includes('network') || message.includes('connection')) {
    return {
      type: 'NETWORK_ERROR',
      retryable: true,
      retryDelay: 60000, // 1 minute
      maxRetries: 5,
      escalationLevel: 'MEDIUM'
    };
  }

  // API quota/limit errors
  if (message.includes('quota') || message.includes('limit exceeded')) {
    return {
      type: 'QUOTA_ERROR',
      retryable: true,
      retryDelay: 3600000, // 1 hour
      maxRetries: 2,
      escalationLevel: 'MEDIUM'
    };
  }

  // Data/validation errors
  if (httpCode === 400 || message.includes('invalid') || message.includes('bad request')) {
    return {
      type: 'DATA_ERROR',
      retryable: false,
      retryDelay: 0,
      maxRetries: 0,
      escalationLevel: 'MEDIUM'
    };
  }

  // Default classification
  return {
    type: 'UNKNOWN_ERROR',
    retryable: true,
    retryDelay: 120000, // 2 minutes
    maxRetries: 2,
    escalationLevel: 'MEDIUM'
  };
}

const classification = classifyError(errorInfo);

// Get retry history from static data
const retryKey = `${workflowId}_${errorInfo.nodeName}_${errorInfo.errorCode}`;
const staticData = $workflow.staticData || {};
const retryHistory = staticData[retryKey] || { count: 0, lastRetry: null };

// Determine if retry should be attempted
const shouldRetry = classification.retryable && retryHistory.count < classification.maxRetries;

// Update retry history
if (shouldRetry) {
  retryHistory.count += 1;
  retryHistory.lastRetry = timestamp;
  staticData[retryKey] = retryHistory;
}

// Create comprehensive error report
const errorReport = {
  ...errorInfo,
  classification,
  retryHistory,
  shouldRetry,
  nextRetryAt: shouldRetry ? new Date(Date.now() + classification.retryDelay).toISOString() : null,
  escalationRequired: !shouldRetry || classification.escalationLevel === 'HIGH'
};

return errorReport;

